#include <stdio.h>
int main() {
    int TC, N, K, Ti, Di;
    scanf("%d", &TC);
    while (TC--) {
        scanf("%d %d", &N, &K);
        int total = 0, time = 0;
        for (int i = 0; i < N; i++) {
            scanf("%d %d", &Ti, &Di);
            if (time >= K) {
                total += Ti * Di;
            }
            time += Ti;
        }
        printf("%d\n", total);
    }
    return 0;
}

