code.Java:
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int TC = sc.nextInt();
        while (TC-- > 0) {
            int N = sc.nextInt(), K = sc.nextInt();
            int total = 0, time = 0;
            for (int i = 0; i < N; i++) {
                int Ti = sc.nextInt(), Di = sc.nextInt();
                if (time >= K) {
                    total += Ti * Di;
                }
                time += Ti;
            }
            System.out.println(total);
        }
    }
}

