const readline = () => lines[idx++];
const TC = parseInt(readline());
for (let i = 0; i < TC; i++) {
    let [N, K] = readline().split(' ').map(Number);
    let total = 0, time = 0;
    for (let j = 0; j < N; j++) {
        let [Ti, Di] = readline().split(' ').map(Number);
        if (time >= K) {
            total += Ti * Di;
        }
        time += Ti;
    }
    console.log(total);
}

